const body = $input.first().json;
const stores = Array.isArray(body) ? body : [];
if (stores.length === 0) throw new Error('No hay tiendas activas');
return stores.map(s => ({ json: s }));

// Extraer productos con regex basado en selectores de la config
// n8n no tiene Cheerio nativo — usamos el HTML que viene como texto
const item = $input.first().json;
const html = typeof item === 'string' ? item : (item.data || item.body || JSON.stringify(item));
const store = $('Loop por Tienda').first().json;
const config = store.scraping_config || {};

if (!html || html.length < 200) {
  return [{ json: {
    store_id: store.id,
    store_name: store.name,
    store_category: store.category,
    base_url: store.url,
    config,
    products_raw: [],
    error: 'HTML vacio o muy corto'
  }}];
}

// Convertir selector CSS a regex aproximado
// Ejemplo: .product-item -> class="...product-item..."
function selectorToPattern(selector) {
  if (!selector) return null;
  const cls = selector.replace(/^[.#]/, '').replace(/-/g, '[-_]?');
  return new RegExp(`class=["'][^"']*${cls}[^"']*["']([\\s\\S]*?)(?=class=["'][^"']*${cls}|$)`, 'gi');
}

// Extraer texto entre tags
function extractText(html, selector) {
  if (!selector || !html) return '';
  const cls = selector.replace(/^[.#]/, '');
  const pattern = new RegExp(`class=["'][^"']*${cls}[^"']*["'][^>]*>([^<]+)<`, 'i');
  const match = html.match(pattern);
  return match ? match[1].trim() : '';
}

// Extraer href
function extractHref(block, baseUrl) {
  const m = block.match(/href=["']([^"']+)["']/);
  if (!m) return '';
  return m[1].startsWith('http') ? m[1] : baseUrl.replace(/\/[^\/]*$/, '') + m[1];
}

// Extraer src de img
function extractImg(block) {
  const m = block.match(/(?:src|data-src)=["']([^"']+\.(?:jpg|jpeg|png|webp))["']/i);
  return m ? m[1] : '';
}

// Limpiar precio
function parsePrice(raw) {
  if (!raw) return NaN;
  const clean = raw.replace(/[^0-9,.]/g, '').replace(/\./g, '').replace(',', '.');
  return parseFloat(clean);
}

const products = [];
const productSelector = config.product_selector || '.product';
const nameSel = config.name_selector || '.name';
const priceSel = config.price_selector || '.price';

// Dividir HTML en bloques de productos
const cls = productSelector.replace(/^[.#]/, '');
const blockPattern = new RegExp(`<[^>]+class=["'][^"']*${cls}[^"']*["'][^>]*>([\\s\\S]{50,2000}?)(?=<[^>]+class=["'][^"']*${cls}|$)`, 'gi');

let match;
while ((match = blockPattern.exec(html)) !== null && products.length < 100) {
  const block = match[0];
  const name = extractText(block, nameSel);
  const priceRaw = extractText(block, priceSel);
  const price = parsePrice(priceRaw);
  if (name && name.length > 2 && !isNaN(price) && price > 0) {
    products.push({
      raw_name: name,
      price,
      product_url: extractHref(block, store.url),
      image_url: extractImg(block)
    });
  }
}

return [{ json: {
  store_id: store.id,
  store_name: store.name,
  store_category: store.category,
  base_url: store.url,
  config,
  products_raw: products,
  total_found: products.length
}}];

const data = $input.first().json;
const products = data.products_raw || [];

if (products.length === 0) {
  return [{ json: { ...data, normalized_products: [], skip_db: true } }];
}

// Procesar en batches de 20 y armar UN solo prompt por batch
// Devolvemos array de batches para que el nodo siguiente los itere
const BATCH_SIZE = 20;
const batches = [];
for (let i = 0; i < products.length; i += BATCH_SIZE) {
  batches.push(products.slice(i, i + BATCH_SIZE));
}

return [{ json: { ...data, batches, current_batch_index: 0, normalized_products: [] } }];

// Procesar TODOS los batches en un solo nodo con loop interno
// Esto evita problemas de contexto entre nodos en n8n
const data = $input.first().json;
const batches = data.batches || [];

if (batches.length === 0) {
  return [{ json: { ...data, normalized_products: [], done: true } }];
}

// Armar prompt para el primer batch pendiente
const idx = data.current_batch_index || 0;
const batch = batches[idx];

const productList = batch
  .map((p, i) => `${i + 1}. "${p.raw_name}" - $${p.price}`)
  .join('\n');

const prompt = `Sos un experto en productos de Argentina. Normalizá estos nombres de productos del rubro "${data.store_category}".

Devolvé SOLO un JSON array con este formato:
[
  {
    "index": 1,
    "canonical_name": "Nombre claro y completo del producto",
    "category": "categoria",
    "subcategory": "subcategoria o null",
    "brand": "marca o null",
    "unit": "litro/kg/unidad/m2/etc o null",
    "quantity": numero o null
  }
]

Productos:
${productList}

Reglas:
- canonical_name debe ser descriptivo: "Pintura Látex Interior Blanco 4L" no "Pint Lat Bco"
- Detectá marca si está en el nombre
- Devolvé SOLO el JSON array, sin texto adicional`;

return [{ json: { ...data, current_batch: batch, prompt, current_batch_index: idx } }];

const groqResp = $input.first().json;
const prev = $('Armar Prompt Batch').first().json;

let normalized = [];
try {
  const content = groqResp.choices[0].message.content;
  const match = content.match(/\[\s*\{[\s\S]*?\}\s*\]/);
  if (match) normalized = JSON.parse(match[0]);
} catch(e) { normalized = []; }

const batch = prev.current_batch || [];
const merged = batch.map((orig, i) => {
  const norm = normalized.find(n => n.index === i + 1) || {};
  return {
    raw_name: orig.raw_name,
    price: orig.price,
    product_url: orig.product_url,
    image_url: orig.image_url,
    canonical_name: norm.canonical_name || orig.raw_name,
    category: norm.category || prev.store_category,
    subcategory: norm.subcategory || null,
    brand: norm.brand || null,
    unit: norm.unit || null,
    quantity: norm.quantity || null
  };
});

const allNormalized = [...(prev.normalized_products || []), ...merged];
const nextIndex = (prev.current_batch_index || 0) + 1;
const done = nextIndex >= (prev.batches || []).length;

return [{ json: {
  ...prev,
  normalized_products: allNormalized,
  current_batch_index: nextIndex,
  done
}}];

const data = $input.first().json;
const storeId = data.store_id;

const productInserts = (data.normalized_products || []).map(p => ({
  store_id: storeId,
  canonical_name: p.canonical_name,
  raw_name: p.raw_name,
  category: p.category,
  subcategory: p.subcategory || null,
  brand: p.brand || null,
  unit: p.unit || null,
  quantity: p.quantity || null,
  product_url: p.product_url || null,
  image_url: p.image_url || null,
  updated_at: new Date().toISOString()
}));

return [{ json: {
  store_id: storeId,
  store_name: data.store_name,
  product_inserts: productInserts,
  prices_map: data.normalized_products.reduce((acc, p) => {
    acc[p.canonical_name] = p.price;
    return acc;
  }, {}),
  total: productInserts.length
}}];

const inserted = $input.first().json;
const prev = $('Preparar Upsert').first().json;
const arr = Array.isArray(inserted) ? inserted : [];

const priceInserts = arr
  .map(p => ({
    product_id: p.id,
    store_id: p.store_id,
    price: prev.prices_map[p.canonical_name] || 0,
    scraped_at: new Date().toISOString()
  }))
  .filter(p => p.price > 0);

return [{ json: {
  store_id: prev.store_id,
  store_name: prev.store_name,
  price_inserts: priceInserts,
  total_products: prev.total,
  total_prices: priceInserts.length
}}];
